/**
 * Atlas Segmented Control
 *
 * A high-fidelity, accessible toggle component for mutually exclusive options.
 * Handles state management, ARIA roles, and keyboard navigation.
 */

export class SegmentedControl {
  constructor(container) {
    if (!container) return;
    this.container = typeof container === 'string' ? document.querySelector(container) : container;
    this.selectedClass = 'segment-item-selected';
    this.disabledClass = 'segment-item-disabled';
    this.callbacks = {
      change: [],
    };

    this.init();
  }

  /**
   * Internal initialization: sets up roles, listeners, and initial state.
   */
  init() {
    const segments = this.container.querySelectorAll('.segment-item');

    // Accessibility setup
    if (!this.container.hasAttribute('role')) {
      this.container.setAttribute('role', 'tablist');
    }

    segments.forEach((segment, index) => {
      if (!segment.hasAttribute('role')) {
        segment.setAttribute('role', 'tab');
      }

      // Initial active state from HTML if present
      const isActive = segment.classList.contains(this.selectedClass);
      segment.setAttribute('aria-selected', isActive ? 'true' : 'false');

      if (!segment.hasAttribute('tabindex')) {
        segment.setAttribute('tabindex', isActive || (!this.value && index === 0) ? '0' : '-1');
      }

      // Click handler
      segment.addEventListener('click', (e) => {
        if (this.isDisabled(segment)) {
          e.preventDefault();
          return;
        }
        this.value = this.getSegmentValue(segment);
      });

      // Keyboard navigation
      segment.addEventListener('keydown', (e) => {
        if (this.isDisabled(segment)) return;

        if (e.key === 'ArrowRight' || e.key === 'ArrowDown') {
          e.preventDefault();
          this.moveFocus(1);
        } else if (e.key === 'ArrowLeft' || e.key === 'ArrowUp') {
          e.preventDefault();
          this.moveFocus(-1);
        } else if (e.key === 'Enter' || e.key === ' ') {
          e.preventDefault();
          this.value = this.getSegmentValue(segment);
        }
      });
    });
  }

  /**
   * Getter for current value.
   */
  get value() {
    const activeSegment = this.container.querySelector(`.${this.selectedClass}`);
    return activeSegment ? this.getSegmentValue(activeSegment) : null;
  }

  /**
   * Setter for current value: updates UI, ARIA, and dispatches events.
   */
  set value(newValue) {
    const segments = Array.from(this.container.querySelectorAll('.segment-item'));
    const target = segments.find(seg => this.getSegmentValue(seg) === newValue);

    if (!target || this.isDisabled(target)) return;

    const oldValue = this.value;
    if (oldValue === newValue) return;

    // Update UI components
    segments.forEach(seg => {
      const isSelected = seg === target;
      seg.classList.toggle(this.selectedClass, isSelected);
      seg.setAttribute('aria-selected', isSelected ? 'true' : 'false');
      seg.setAttribute('tabindex', isSelected ? '0' : '-1');
    });

    // Notify listeners
    this.dispatchEvent(newValue);
  }

  /**
   * Internal helper to extract value from a segment.
   */
  getSegmentValue(segment) {
    // Priority: data-value > value (if button) > text content
    return segment.getAttribute('data-value') || segment.value || segment.textContent.trim();
  }

  /**
   * Check if a segment is disabled.
   */
  isDisabled(segment) {
    return (
      segment.disabled ||
      segment.classList.contains(this.disabledClass) ||
      segment.hasAttribute('disabled')
    );
  }

  /**
   * Register event listeners (Better DX).
   */
  on(event, callback) {
    if (this.callbacks[event]) {
      this.callbacks[event].push(callback);
    }
    return this;
  }

  /**
   * Internal event dispatcher.
   */
  dispatchEvent(value) {
    // 1. Better DX callbacks
    this.callbacks.change.forEach(cb => cb(value));

    // 2. Standard DOM event for generic integration
    const event = new CustomEvent('change', {
      detail: { value },
      bubbles: true
    });
    this.container.dispatchEvent(event);
  }

  /**
   * Accessibility: moves focus between segments.
   */
  moveFocus(direction) {
    const segments = Array.from(this.container.querySelectorAll('.segment-item'))
      .filter(seg => !this.isDisabled(seg));

    if (segments.length === 0) return;

    let currentIndex = segments.indexOf(document.activeElement);
    
    // Fallback if focus is not on a segment (e.g. initial tab in)
    if (currentIndex === -1) {
      const activeSegment = this.container.querySelector(`.${this.selectedClass}`);
      currentIndex = activeSegment ? segments.indexOf(activeSegment) : 0;
    }

    let nextIndex = currentIndex + direction;

    if (nextIndex < 0) nextIndex = segments.length - 1;
    if (nextIndex >= segments.length) nextIndex = 0;

    segments[nextIndex].focus();
  }
}

/**
 * Factory initialization
 */
export function initSegmentedControl(element) {
  return new SegmentedControl(element);
}
