/**
 * Atlas Tabs Component
 * 
 * Handles interactive logic for tabbed navigation, including selection states,
 * ARIA roles for accessibility, and keyboard navigation.
 */

export class Tabs {
  constructor(container) {
    if (!container) return;
    this.container = typeof container === 'string' ? document.querySelector(container) : container;
    this.selectedClass = 'is-selected';
    this.disabledClass = 'is-disabled';
    this.callbacks = {
      change: [],
    };

    this.init();
  }

  /**
   * Internal initialization: sets up roles, listeners, and initial state.
   */
  init() {
    const tabButtons = this.container.querySelectorAll('.bl-tab');

    // Accessibility setup for the container
    if (!this.container.hasAttribute('role')) {
      this.container.setAttribute('role', 'tablist');
    }

    // Determine if vertical orientation
    const isVertical = this.container.classList.contains('bl-tabs-list--vertical');
    if (isVertical && !this.container.hasAttribute('aria-orientation')) {
      this.container.setAttribute('aria-orientation', 'vertical');
    }

    tabButtons.forEach((tab, index) => {
      // Accessibility setup for each tab
      if (!tab.hasAttribute('role')) {
        tab.setAttribute('role', 'tab');
      }

      const isActive = tab.classList.contains(this.selectedClass);
      tab.setAttribute('aria-selected', isActive ? 'true' : 'false');

      if (!tab.hasAttribute('tabindex')) {
        tab.setAttribute('tabindex', isActive || (index === 0 && !this.container.querySelector(`.${this.selectedClass}`)) ? '0' : '-1');
      }

      // Click handler
      tab.addEventListener('click', (e) => {
        if (this.isDisabled(tab)) {
          e.preventDefault();
          return;
        }
        this.selectTab(tab);
      });

      // Keyboard navigation
      tab.addEventListener('keydown', (e) => {
        if (this.isDisabled(tab)) return;

        // In a tablist, we usually use arrows to move focus
        if (e.key === 'ArrowRight' || e.key === 'ArrowDown') {
          e.preventDefault();
          this.moveFocus(1);
        } else if (e.key === 'ArrowLeft' || e.key === 'ArrowUp') {
          e.preventDefault();
          this.moveFocus(-1);
        } else if (e.key === 'Enter' || e.key === ' ') {
          e.preventDefault();
          this.selectTab(tab);
        } else if (e.key === 'Home') {
          e.preventDefault();
          this.moveFocusToExtreme('first');
        } else if (e.key === 'End') {
          e.preventDefault();
          this.moveFocusToExtreme('last');
        }
      });
    });
  }

  /**
   * Selects a specific tab element.
   */
  selectTab(tabElement) {
    if (!tabElement || this.isDisabled(tabElement) || tabElement.classList.contains(this.selectedClass)) {
      return;
    }

    const tabButtons = Array.from(this.container.querySelectorAll('.bl-tab'));
    const oldValue = this.getActiveValue();

    tabButtons.forEach(tab => {
      const isTarget = tab === tabElement;
      tab.classList.toggle(this.selectedClass, isTarget);
      tab.setAttribute('aria-selected', isTarget ? 'true' : 'false');
      tab.setAttribute('tabindex', isTarget ? '0' : '-1');
    });

    const newValue = this.getActiveValue();
    this.dispatchEvent(newValue, oldValue, tabElement);
  }

  /**
   * Helper to get the value of the currently active tab.
   */
  getActiveValue() {
    const activeTab = this.container.querySelector(`.${this.selectedClass}`);
    if (!activeTab) return null;
    return activeTab.getAttribute('data-value') || activeTab.textContent.trim();
  }

  /**
   * Check if a tab is disabled.
   */
  isDisabled(tab) {
    return (
      tab.disabled ||
      tab.classList.contains(this.disabledClass) ||
      tab.hasAttribute('disabled')
    );
  }

  /**
   * Getter for current value.
   */
  get value() {
    return this.getActiveValue();
  }

  /**
   * Setter for current value: updates UI, ARIA, and dispatches events.
   */
  set value(newValue) {
    const tabs = Array.from(this.container.querySelectorAll('.bl-tab'));
    const target = tabs.find(tab => {
      const val = tab.getAttribute('data-value') || tab.textContent.trim();
      return val === newValue;
    });

    if (target) {
      this.selectTab(target);
    }
  }

  /**
   * Register event listeners.
   */
  on(event, callback) {
    if (this.callbacks[event]) {
      this.callbacks[event].push(callback);
    }
    return this;
  }

  /**
   * Internal event dispatcher.
   */
  dispatchEvent(newValue, oldValue, element) {
    const detail = { newValue, oldValue, element };
    
    this.callbacks.change.forEach(cb => cb(detail));

    const event = new CustomEvent('tab:change', {
      detail,
      bubbles: true
    });
    this.container.dispatchEvent(event);
  }

  /**
   * Move focus between tabs.
   */
  moveFocus(direction) {
    const tabs = Array.from(this.container.querySelectorAll('.bl-tab'))
      .filter(tab => !this.isDisabled(tab));

    if (tabs.length === 0) return;

    let currentIndex = tabs.indexOf(document.activeElement);
    if (currentIndex === -1) {
      const activeTab = this.container.querySelector(`.${this.selectedClass}`);
      currentIndex = activeTab ? tabs.indexOf(activeTab) : 0;
    }

    let nextIndex = currentIndex + direction;
    if (nextIndex < 0) nextIndex = tabs.length - 1;
    if (nextIndex >= tabs.length) nextIndex = 0;

    tabs[nextIndex].focus();
  }

  /**
   * Move focus to first or last tab.
   */
  moveFocusToExtreme(target) {
    const tabs = Array.from(this.container.querySelectorAll('.bl-tab'))
      .filter(tab => !this.isDisabled(tab));

    if (tabs.length === 0) return;

    if (target === 'first') {
      tabs[0].focus();
    } else {
      tabs[tabs.length - 1].focus();
    }
  }
}

/**
 * Factory initialization
 */
export function initTabs(element) {
  return new Tabs(element);
}
