/**
 * Atlas Modal Component
 * 
 * Provides high-fidelity logic for managing modal visibility, 
 * accessibility (Esc key), and backdrop interactions.
 */

export class Modal {
  constructor(element) {
    if (!element) return;
    this.modal = typeof element === 'string' ? document.querySelector(element) : element;
    
    if (!this.modal) {
      console.warn(`Atlas Modal: Element "${element}" not found.`);
      return;
    }

    // Guard against double-initialization
    if (this.modal.__atlas_init) return this.modal.__atlas_instance;
    this.modal.__atlas_init = true;

    // The modal element should be the container (.modal-backdrop)
    this.container = this.modal;
    this.inner = this.modal.querySelector('.modal');
    this.closeButtons = Array.from(this.modal.querySelectorAll('[data-modal-close]'));
    
    this.init();
    this.modal.__atlas_instance = this;
  }

  init() {
    // Handle close buttons
    this.closeButtons.forEach(btn => {
      btn.addEventListener('click', (e) => {
        e.preventDefault();
        this.close();
      });
    });

    // Handle backdrop click
    this.container.addEventListener('click', (e) => {
      // Only close if clicking exactly the backdrop, not the modal content
      if (e.target === this.container) {
        this.close();
      }
    });

    // Handle Escape key
    this.escHandler = (e) => {
      if (e.key === 'Escape' && this.isOpen()) {
        this.close();
      }
    };
    document.addEventListener('keydown', this.escHandler);
  }

  destroy() {
    document.removeEventListener('keydown', this.escHandler);
    this.modal.__atlas_init = false;
    this.modal.__atlas_instance = null;
  }

  open() {
    this.container.classList.add('is-open');
    document.body.style.overflow = 'hidden'; // Prevent scrolling
    
    // Focus management (optional but good for accessibility)
    const firstInput = this.inner.querySelector('input, textarea, button:not([disabled])');
    if (firstInput) {
      setTimeout(() => firstInput.focus(), 100);
    }
  }

  close() {
    this.container.classList.remove('is-open');
    document.body.style.overflow = '';
  }

  toggle() {
    this.isOpen() ? this.close() : this.open();
  }

  isOpen() {
    return this.container.classList.contains('is-open');
  }
}

/**
 * Factory initialization
 */
export function initModal(element) {
  return new Modal(element);
}
